def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-9
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 3:
            base = np.exp(ratio) / (capacity + 1)
            for x in range(1, int(capacity) + 3):
                if x % 5 == 0:
                    base += np.tanh(ratio * x) * 3
                elif x % 2 == 1:
                    base -= np.sin(ratio / (x + epsilon)) ** 2
                else:
                    base += np.log(x + ratio + epsilon) / (x + 1)
            if base < 0:
                priority = abs(base) * 2.5
            else:
                priority = base * 1.7
            if capacity % 4 == 0:
                priority /= 1.3
            else:
                priority *= 1.2
        elif 2 < ratio <= 3:
            priority = (np.sqrt(ratio) + np.log(capacity + 1)) * (capacity / (item + epsilon))
            for y in range(1, int(item) * 2 + 1):
                if y % 4 == 0:
                    priority += (np.cos(y / (capacity + 1)) + y / (item + epsilon)) ** 1.5
                elif y % 3 == 0:
                    priority -= (y ** 1.1) / (capacity + epsilon)
                else:
                    priority += np.log(y + ratio + epsilon) / (y + 1)
            priority = max(priority, 0)
            if priority > 50:
                priority /= np.sqrt(priority)
        elif 1 < ratio <= 2:
            priority = (ratio ** 3) * np.sin(capacity + 1)
            factor = 1
            for n in range(1, 7):
                mul = (ratio + n / (capacity + 1)) * np.cos(n)
                factor *= mul if mul > 0 else 1
                if factor > 10:
                    break
            priority *= factor
            if capacity % 3 == 1:
                priority += np.log(priority + epsilon) * 2
            else:
                priority -= np.sqrt(priority + epsilon)
            priority = max(priority, 0)
        elif 0.5 < ratio <= 1:
            accumulator = 0
            for z in range(1, int(capacity) + 2):
                term = ((-1) ** z) * (ratio ** z) / (z + epsilon)
                accumulator += term
                if abs(term) < 1e-4:
                    break
            priority = abs(accumulator) * np.log(capacity + 2)
            if priority < 0.1:
                priority += ratio ** 2
        else:
            priority = 1 / (ratio + epsilon) * np.exp(-capacity / (item + epsilon))
            steps = int(capacity / 2) + 1
            for w in range(1, steps):
                if w % 2 == 0:
                    priority += np.tan(ratio / (w + epsilon)) * 0.7
                else:
                    priority -= np.sqrt(w / (capacity + 1))
            if priority < 0:
                priority = abs(priority) + 1
        if capacity < item:
            diff = item - capacity
            penalty = diff ** 2 * 20
            for p in range(1, int(diff) + 3):
                if p % 3 == 0:
                    penalty += np.exp(-p / (diff + epsilon)) * 5
                elif p % 2 == 0:
                    penalty -= np.sqrt(p)
                else:
                    penalty += np.log(p + diff + 1)
            penalty = max(penalty, 0)
            priority += penalty
        if priority != priority or priority == np.inf or priority == -np.inf:
            priority = 1e6
        priorities[i] = priority
    return priorities
